/**
 * PaymentSchema
 *
 * Public representation of a Payment record.
 */
export type PaymentSchema = {
    status: PaymentStatus;
    /**
     * Currency
     */
    currency: 'EUR' | 'USD' | 'GBP' | 'JPY' | 'AUD' | 'CAD' | 'CHF' | 'CNY' | 'HKD' | 'NZD' | 'SEK' | 'KRW' | 'SGD' | 'NOK' | 'MXN' | 'INR' | 'ZAR' | 'TRY' | 'BRL' | 'DKK' | 'PLN' | 'THB' | 'IDR' | 'HUF' | 'CZK' | 'ILS' | 'MYR' | 'PHP' | 'RON' | 'ISK';
    /**
     * Stripe Dashboard Url
     */
    stripe_dashboard_url: string;
    /**
     * Id
     */
    id?: string | null;
    /**
     * Created At
     */
    created_at: string;
    /**
     * Updated At
     */
    updated_at: string;
    /**
     * Stripe Session Id
     */
    stripe_session_id: string;
    /**
     * Stripe Payment Intent Id
     *
     * Stripe PaymentIntent ID for refund processing
     */
    stripe_payment_intent_id?: string | null;
    /**
     * Amount
     */
    amount: string;
    /**
     * Platform Fee
     */
    platform_fee: string;
    /**
     * Net Amount
     *
     * Ticket price excluding VAT.
     */
    net_amount?: string | null;
    /**
     * Vat Amount
     *
     * VAT portion of the ticket price.
     */
    vat_amount?: string | null;
    /**
     * Vat Rate
     *
     * VAT rate snapshot at purchase time.
     */
    vat_rate?: string | null;
    /**
     * Platform Fee Net
     *
     * Platform fee excluding VAT.
     */
    platform_fee_net?: string | null;
    /**
     * Platform Fee Vat
     *
     * VAT portion of the platform fee.
     */
    platform_fee_vat?: string | null;
    /**
     * Platform Fee Vat Rate
     *
     * Platform fee VAT rate snapshot.
     */
    platform_fee_vat_rate?: string | null;
    /**
     * Platform Fee Reverse Charge
     *
     * Whether reverse charge applies to the platform fee (EU B2B cross-border).
     */
    platform_fee_reverse_charge?: boolean;
    /**
     * Buyer Billing Snapshot
     *
     * Buyer billing info snapshot at checkout time for attendee invoice generation.
     */
    buyer_billing_snapshot?: {
        [key: string]: unknown;
    } | null;
    /**
     * Refund Amount
     *
     * Actual amount refunded. May be less than amount when a partial refund policy applies.
     */
    refund_amount?: string | null;
    /**
     * Refund Status
     */
    refund_status?: string | null;
    /**
     * Stripe Refund Id
     *
     * Stripe refund object id. Used to match webhook refund events to this Payment.
     */
    stripe_refund_id?: string | null;
    /**
     * Refund Failure Reason
     */
    refund_failure_reason?: string | null;
    /**
     * Refunded At
     */
    refunded_at?: string | null;
    /**
     * Expires At
     */
    expires_at?: string;
};

